I18N.register("ro", {
  tips: {
    "Look at Rows and Columns Separately": ["Uită-te la rânduri și coloane separat", "Într-o grilă cu numere, verifică mai întâi fiecare rând, apoi fiecare coloană. Adesea o direcție urmează o regulă simplă: numără din 2 în 2 sau din 3 în 3."],
    "Find the Rule Between Numbers": ["Găsește regula dintre numere", "Întreabă-te: ce adun, scad, înmulțesc sau împart ca să trec de la un număr la următorul? Încearcă fiecare operație până găsești una care merge la fiecare pas."],
    "Watch for Repeating Groups": ["Fii atent la grupuri care se repetă", "Uneori un grup de forme sau simboli se repetă la nesfârșit. Numără câte elemente are grupul, apoi vezi unde ești în ciclu."],
    "Use Elimination": ["Folosește eliminarea", "Dacă nu ești sigur, încearcă fiecare variantă de răspuns: pune-o în tipar și vezi dacă regula încă funcționează. Elimină orice răspuns care strică tiparul."],
    "Find the Difference": ["Caută diferența", "Scade fiecare număr din cel de dinaintea lui. Dacă diferența e mereu aceeași, regula e o adunare sau o scădere simplă."],
    "Try Multiplying or Dividing": ["Încearcă să înmulțești sau să împarți", "Împarte fiecare număr la cel dinainte. Dacă obții același rezultat de fiecare dată, șirul se înmulțește sau se împarte cu același factor."],
    "Check for Two-Step Rules": ["Verifică reguli în doi pași", "Uneori regula combină două operații (de ex. întâi +2, apoi ×2). Scrie pașii pe ciornă și urmărește-i în ordine."],
    "Write It Down": ["Notează pe hârtie", "Scrie numerele și diferențele sau rapoartele sub ele. Pe hârtie vezi mai ușor tiparul decât doar din ochi."],
    "Read Every Word Carefully": ["Citește fiecare cuvânt cu atenție", "La logică, detaliile contează: cuvinte mici ca «toți», «unii», «niciun», «sigur» schimbă sensul. Citește întrebarea de două ori înainte să alegi."],
    "Draw a Picture or List": ["Desenează sau fă o listă", "Schitează persoanele, zilele sau relațiile din problemă. O listă sau un desen simplu arată clar cine e mai mare, cine vine înainte etc."],
    "Watch Out for Traps": ["Fii atent la capcane", "Din «toți câinii sunt animale» nu rezultă «toate animalele sunt câini». Nu inversa regula din greșeală."],
    "Use 'If... Then...' Thinking": ["Gândește în modul «dacă… atunci…»", "Reformulează afirmațiile ca «dacă A, atunci B». Urmărește lanțul: dacă A e adevărat, ce trebuie să fie adevărat mai departe?"],
    "Picture It in Your Mind": ["Imaginează-ți în minte", "Pentru forme și cuburi, încearcă să «vezi» rotirea sau plierea. Poți desena pe ciornă o schiță rapidă."],
    "Know the Basics of Common Shapes": ["Știe bazele formelor uzuale", "Cubul are 6 fețe, 12 muchii, 8 vârfuri. Prisma triunghiulară are 5 fețe. Repetă aceste fapte și devin automate."],
    "Count What You Cannot See": ["Numără și ce nu se vede", "La cuburi lipite, fețele ascunse unde se ating nu se numără la fețe vizibile. Scade fețele «lipite» din total."],
    "Use Nets to Understand Folding": ["Folosește desfășurata ca să înțelegi plierea", "Desfășurata («pătratul» tăiat care se pliază în cub) arată care fețe sunt vecine. Urmărește o față și vezi cu care se lipește."],
    "Read the Problem Twice": ["Citește problema de două ori", "Multe probleme capcană se bazează pe grăbitură. A doua citire prinde formulări ca «toate în afară de…» sau «rămân»."],
    "Look for Trick Words": ["Caută cuvinte-cheie capcană", "Expresii ca «toate în afară de», «rămân», «în total», «fiecare» schimbă socoteala. Sublinează-le."],
    "Break It Into Steps": ["Împarte în pași", "Rezolvă pe rând: întâi ce știi sigur, apoi adună sau scade conform problemei. Nu încerca totul dintr-o dată."],
    "Check Your Answer": ["Verifică răspunsul", "După ce calculezi, întoarce-te la întrebare: răspunsul are sens în poveste? Refă calculul încă o dată dacă e nevoie."],
  },
  q: {
    "TPR811_1_01": ["Ce urmează în șir? 2, 4, 6, 8, __", "Numără din 2 în 2.", ["9", "10", "12", "11"], "Șirul crește din 2 la fiecare pas: 2, 4, 6, 8, 10."],
    "TPR811_1_02": ["Ce urmează? 5, 10, 15, 20, __", "Numerele sunt multiplii aceluiași număr de bază.", ["22", "30", "25", "24"], "Șirul crește din 5 la fiecare pas: 5, 10, 15, 20, 25."],
    "TPR811_1_03": ["Ce urmează? 3, 6, 9, 12, __", "Gândește-te la înmulțirea cu 3 (tabla cu 3).", ["14", "15", "16", "13"], "Șirul crește din 3 la fiecare pas: 3, 6, 9, 12, 15."],
    "TPR811_1_04": ["Ce urmează? 10, 20, 30, 40, __", "Numără din 10 în 10.", ["45", "55", "50", "60"], "Șirul crește din 10 la fiecare pas: 10, 20, 30, 40, 50."],
    "TPR811_1_05": ["Ce urmează? 4, 8, 12, 16, __", "Sunt multiplii lui 4.", ["18", "22", "24", "20"], "Șirul crește din 4 la fiecare pas: 4, 8, 12, 16, 20."],
    "TPR811_1_06": ["Care este numărul lipsă? 1, 3, 5, __, 9", "Sunt numere impare.", ["6", "8", "7", "4"], "Sunt numere impare care cresc din 2 în 2: 1, 3, 5, 7, 9."],
    "TPR811_1_07": ["Ce urmează? 2, 5, 8, 11, __", "Cu cât se adună de fiecare dată?", ["12", "13", "15", "14"], "Fiecare număr este cu 3 mai mare decât precedentul: 2, 5, 8, 11, 14."],
    "TPR811_1_08": ["Care este numărul lipsă? 6, 12, __, 24, 30", "Numără din 6 în 6.", ["15", "18", "20", "16"], "Șirul crește din 6: 6, 12, 18, 24, 30."],
    "TPR811_1_09": ["Ce urmează în șir? ○, □, ○, □, ○, __", "Formele se alternează.", ["○", "△", "□", "◇"], "Cercul și pătratul se alternează. După cerc urmează pătratul: ○, □, ○, □, ○, □."],
    "TPR811_1_10": ["Ce urmează? 7, 14, 21, 28, __", "Gândește-te la înmulțirea cu 7 (tabla cu 7).", ["30", "32", "36", "35"], "Șirul crește din 7 la fiecare pas: 7, 14, 21, 28, 35."],
    "TPR811_1_11": ["Care este numărul lipsă? 10, __, 30, 40, 50", "Numără din 10 în 10.", ["15", "25", "20", "12"], "Șirul crește din 10: 10, 20, 30, 40, 50."],
    "TPR811_1_12": ["Ce urmează? 1, 4, 7, 10, __", "Cu cât se adună de fiecare dată?", ["12", "14", "11", "13"], "Fiecare număr este cu 3 mai mare decât precedentul: 1, 4, 7, 10, 13."],
    "TPR811_1_13": ["Ce urmează în șir? A, B, A, B, A, __", "Literele se alternează.", ["A", "C", "B", "D"], "A și B alternate: A, B, A, B, A, B."],
    "TPR811_1_14": ["Ce urmează? 8, 16, 24, 32, __", "Sunt multiplii lui 8.", ["36", "38", "40", "42"], "Șirul crește din 8: 8, 16, 24, 32, 40."],
    "TPR811_1_15": ["Care este numărul lipsă? 5, 10, __, 20, 25", "Numără din 5 în 5.", ["12", "14", "16", "15"], "Șirul crește din 5: 5, 10, 15, 20, 25."],
    "TPR811_1_16": ["Ce urmează? 9, 18, 27, 36, __", "Sunt multiplii lui 9.", ["45", "40", "42", "44"], "Șirul crește din 9: 9, 18, 27, 36, 45."],
    "TPR811_1_17": ["Ce urmează în șir? ★, ♥, ★, ♥, ★, __", "Două simboluri se alternează.", ["★", "♥", "♦", "○"], "Stea și heart alternate: ★, ♥, ★, ♥, ★, ♥."],
    "TPR811_1_18": ["Care este numărul lipsă? 2, 4, __, 8, 10", "Numără din 2 în 2.", ["5", "7", "6", "3"], "Șirul crește din 2: 2, 4, 6, 8, 10."],
    "TPR811_1_19": ["Ce urmează? 11, 22, 33, 44, __", "Sunt multiplii lui 11.", ["50", "55", "54", "56"], "Șirul crește din 11: 11, 22, 33, 44, 55."],
    "TPR811_1_20": ["Ce urmează în șir? 1, 2, 1, 2, 1, __", "Numerele se repetă mereu la fel.", ["1", "3", "2", "0"], "Numerele 1 și 2 alternate: 1, 2, 1, 2, 1, 2."],
    "TPR811_2_01": ["In a grid, rândul 1 este: 2, 4, 6, 8. rândul 2 este: 3, 6, 9, 12. rândul 3 este: 4, 8, __, 16. Care este numărul lipsă?", "Fiecare rând conține multiplii primului număr din acel rând.", ["10", "11", "12", "14"], "Rândul 3 conține multiplii of 4: 4, 8, 12, 16."],
    "TPR811_2_02": ["Ce urmează? 1, 2, 4, 8, __", "Fiecare număr este doubled.", ["10", "12", "14", "16"], "Fiecare număr se înmulțește cu 2: 1, 2, 4, 8, 16."],
    "TPR811_2_03": ["Ce urmează? 3, 9, 27, __", "Fiecare număr se înmulțește cu același factor.", ["36", "54", "81", "30"], "Fiecare număr se înmulțește cu 3: 3, 9, 27, 81."],
    "TPR811_2_04": ["Ce urmează în șirul de simboluri? △, △, □, △, △, □, △, △, __", "Găsește grupul de simboluri care se repetă.", ["△", "□", "○", "★"], "Tiparul se repetă △, △, □ mereu la fel. Poziția 9 este □."],
    "TPR811_2_05": ["Grilă: Rândul 1 este 1, 2, 3. rândul 2 este 2, 4, 6. rândul 3 este 3, 6, __. Care este numărul lipsă?", "Fiecare rând înmulțește primul rând cu numărul rândului.", ["7", "8", "9", "10"], "Rândul 3 = top row × 3. So 3 × 3 = 9."],
    "TPR811_2_06": ["Ce urmează? 2, 6, 18, 54, __", "Înmulțește de fiecare dată cu același număr.", ["108", "162", "72", "60"], "Fiecare număr se înmulțește cu 3: 2, 6, 18, 54, 162."],
    "TPR811_2_07": ["Ce urmează? 64, 32, 16, __", "Fiecare număr se înjumătățește.", ["12", "10", "4", "8"], "Fiecare număr se împarte la 2: 64, 32, 16, 8."],
    "TPR811_2_08": ["Grilă: Rândul 1 este 1, 3, 5, 7. rândul 2 este 2, 6, 10, 14. rândul 3 este 3, 9, __, 21. Care este numărul lipsă?", "Rândul 2 = Rândul 1 × 2. Cât este Rândul 3?", ["12", "15", "13", "17"], "Rândul 3 = Rândul 1 × 3. So 5 × 3 = 15."],
    "TPR811_2_09": ["Ce urmează? 4, 8, 16, 32, __", "Fiecare număr se dublează.", ["48", "40", "64", "36"], "Fiecare număr se înmulțește cu 2: 4, 8, 16, 32, 64."],
    "TPR811_2_10": ["Ce urmează în șir? ★, ♦, ♦, ★, ♦, ♦, ★, ♦, ♦, ★, __", "Găsește grupul care se repetă.", ["★", "♦", "○", "□"], "Tiparul se repetă ★, ♦, ♦. Poziția 11 este ♦."],
    "TPR811_2_11": ["Ce urmează? 5, 25, 125, __", "Înmulțește de fiecare dată cu același număr.", ["150", "500", "250", "625"], "Fiecare număr se înmulțește cu 5: 5, 25, 125, 625."],
    "TPR811_2_12": ["Grilă: Rândul 1 este 2, 4, 6. rândul 2 este 3, 6, 9. rândul 3 este 5, 10, __. Care este numărul lipsă?", "Fiecare rând conține multiplii primului număr din acel rând.", ["12", "14", "15", "20"], "Rândul 3 conține multiplii of 5: 5, 10, 15."],
    "TPR811_2_13": ["Ce urmează? 1, 4, 9, 16, __", "Sunt pătrate perfecte: 1², 2², 3², 4²...", ["20", "25", "24", "36"], "Acestea sunt square numbers: 1, 4, 9, 16, 25 (which are 1², 2², 3², 4², 5²)."],
    "TPR811_2_14": ["Ce urmează în șir? A, A, B, A, A, B, A, A, B, __", "Găsește grupul de 3 care se repetă.", ["A", "B", "C", "D"], "Tiparul se repetă A, A, B. Poziția 10 începe un grup nou care începe cu A."],
    "TPR811_2_15": ["Ce urmează? 1, 1, 2, 3, 5, 8, __", "Adună cele două numere anterioare.", ["10", "11", "12", "13"], "Fiecare număr este suma celor două dinaintea lui: 5 + 8 = 13. Acesta este șirul lui Fibonacci."],
    "TPR811_2_16": ["Grilă: Rândul 1 este 1, 2, 3, 4. rândul 2 este 2, 4, 6, 8. rândul 3 este 4, 8, __, 16. Care este numărul lipsă?", "Rândul 3 = Rândul 1 × 4.", ["10", "12", "14", "9"], "Rândul 3 = Rândul 1 × 4. So 3 × 4 = 12."],
    "TPR811_2_17": ["Ce urmează? 10, 100, 1000, __", "Înmulțește cu 10 la fiecare pas.", ["1100", "2000", "10000", "5000"], "Fiecare număr este înmulțit cu 10: 10, 100, 1000, 10000."],
    "TPR811_2_18": ["Ce urmează? 1, 3, 6, 10, __", "Uită-te la diferențe: +2, +3, +4…", ["13", "14", "15", "12"], "Diferența crește cu 1 la fiecare pas: +2, +3, +4, +5. So 10 + 5 = 15. Acestea sunt numere triunghiulare."],
    "TPR811_2_19": ["Ce urmează? 1000, 500, 250, 125, __", "Fiecare număr se înjumătățește.", ["62.5", "100", "75", "60"], "Fiecare număr se împarte la 2: 1000, 500, 250, 125, 62.5."],
    "TPR811_2_20": ["Ce urmează? 1, 8, 27, 64, __", "Acestea sunt cube numbers: 1³, 2³, 3³, 4³...", ["100", "81", "125", "216"], "Acestea sunt cube numbers: 1³=1, 2³=8, 3³=27, 4³=64, 5³=125."],
    "TPR811_3_01": ["Ce urmează? 1, 3, 7, 15, __", "Try multiplying by 2 și apoi adding 1.", ["29", "30", "31", "23"], "Rule: ×2 apoi +1. 1→3, 3→7, 7→15, 15→31."],
    "TPR811_3_02": ["Ce urmează? 2, 5, 11, 23, __", "Try ×2 apoi +1.", ["35", "46", "47", "45"], "Rule: ×2 apoi +1. 2→5, 5→11, 11→23, 23→47."],
    "TPR811_3_03": ["Ce urmează în șir? ○, ○, □, △, ○, ○, □, △, ○, ○, __", "Găsește grupul de 4 simboluri care se repetă.", ["○", "△", "□", "★"], "Tiparul se repetă: ○, ○, □, △. Poziția 11 este □."],
    "TPR811_3_04": ["Ce urmează? 1, 4, 13, 40, __", "Try ×3 apoi +1.", ["80", "121", "120", "81"], "Rule: ×3 apoi +1. 1→4, 4→13, 13→40, 40→121."],
    "TPR811_3_05": ["Grilă: Rândul 1 este 1, 4, 7. rândul 2 este 3, 10, 17. rândul 3 este 5, 16, __. Fiecare rând urmează aceeași regulă de adunare, iar coloana 1 are valorile 1, 3, 5. Care este numărul lipsă?", "Rândul 1 adună 3 la fiecare pas. Rândul 2 adună 7 la fiecare pas. Rândul 3 adună... uită-te la primele două numere.", ["27", "25", "21", "23"], "Rândul 3: 5, 16, 27. Diferența este 11 la fiecare pas (5+11=16, 16+11=27)."],
    "TPR811_3_06": ["Ce urmează? 2, 6, 14, 30, __", "Try ×2 apoi +2.", ["58", "60", "62", "56"], "Rule: ×2 apoi +2. 2→6, 6→14, 14→30, 30→62."],
    "TPR811_3_07": ["Ce urmează? 3, 7, 15, 31, __", "Try ×2 apoi +1.", ["47", "62", "63", "60"], "Rule: ×2 apoi +1. 3→7, 7→15, 15→31, 31→63."],
    "TPR811_3_08": ["Ce urmează? 1, 2, 5, 10, 17, __", "Uită-te la diferențe între numere: 1, 3, 5, 7...", ["24", "25", "26", "22"], "Diferențele sunt numere impare: +1, +3, +5, +7, +9. So 17 + 9 = 26."],
    "TPR811_3_09": ["Grilă: Rândul 1 este 1, 4, 7. rândul 2 este 2, 8, 14. rândul 3 este 3, 12, __. Care este numărul lipsă?", "Rândul 2 = Rândul 1 × 2. Rândul 3 = Rândul 1 × ?", ["18", "21", "15", "24"], "Rândul 3 = Rândul 1 × 3. So 7 × 3 = 21."],
    "TPR811_3_10": ["Ce urmează? 0, 1, 3, 7, 15, __", "Try ×2 apoi +1.", ["31", "30", "23", "29"], "Rule: ×2 apoi +1. 0→1, 1→3, 3→7, 7→15, 15→31."],
    "TPR811_3_11": ["Ce urmează? 2, 3, 5, 9, 17, __", "Uită-te la diferențe: they double la fiecare pas.", ["25", "33", "31", "34"], "Diferențele se dublează: +1, +2, +4, +8, +16. So 17 + 16 = 33."],
    "TPR811_3_12": ["Ce urmează? 1, 2, 6, 24, __", "1×2=2, 2×3=6, 6×4=24, 24×?...", ["48", "120", "96", "30"], "Înmulțește cu numere din ce în ce mai mari: ×2, ×3, ×4, ×5. So 24 × 5 = 120."],
    "TPR811_3_13": ["Grilă: Rândul 1 este 2, 3, 4. rândul 2 este 5, 7, 9. rândul 3 este 11, 15, __. The rule între rows is ×2 apoi +1. Care este numărul lipsă?", "Aplică regula to each number in Rândul 2.", ["17", "18", "19", "21"], "9 × 2 + 1 = 19."],
    "TPR811_3_14": ["Ce urmează? 100, 98, 94, 86, 70, __", "Look at how much is subtracted: 2, 4, 8, 16...", ["54", "38", "50", "42"], "Scadeions double: −2, −4, −8, −16, −32. So 70 − 32 = 38."],
    "TPR811_3_15": ["Ce urmează? 1, 4, 10, 22, __", "Try ×2 apoi +2.", ["44", "46", "34", "40"], "Rule: ×2 apoi +2. 1→4, 4→10, 10→22, 22→46."],
    "TPR811_3_16": ["Ce urmează? 5, 11, 23, 47, __", "Try ×2 apoi +1.", ["94", "95", "93", "96"], "Rule: ×2 apoi +1. 5→11, 11→23, 23→47, 47→95."],
    "TPR811_3_17": ["Ce urmează? 1, 2, 4, 7, 11, 16, __", "Diferența crește cu 1 la fiecare pas: +1, +2, +3, +4, +5...", ["21", "22", "20", "23"], "Differences: +1, +2, +3, +4, +5, +6. So 16 + 6 = 22."],
    "TPR811_3_18": ["Coloanele grilei: coloana 1 este 1, 2, 4. coloana 2 este 1, 3, 9. coloana 3 este 1, 4, __. Care este numărul lipsă?", "coloana 1 este powers of 2. coloana 2 este powers of 3. coloana 3 este powers of ?", ["8", "12", "16", "20"], "coloana 3 este powers of 4: 4⁰=1, 4¹=4, 4²=16."],
    "TPR811_3_19": ["Ce urmează? 2, 5, 14, 41, __", "Try ×3 apoi −1.", ["82", "122", "123", "124"], "Rule: ×3 apoi −1. 2→5, 5→14, 14→41, 41→122."],
    "TPR811_3_20": ["Ce urmează? 1, 3, 9, 27, 81, __", "Fiecare număr este înmulțit cu 3.", ["162", "243", "108", "100"], "Fiecare număr este ×3: 1, 3, 9, 27, 81, 243."],
    "TNR811_1_01": ["Cât face 3 × 4?", "Gândește-te la 3 groups of 4.", ["7", "10", "12", "14"], "3 × 4 = 12."],
    "TNR811_1_02": ["Cât face 5 × 6?", "Gândește-te la 5 groups of 6.", ["25", "30", "35", "36"], "5 × 6 = 30."],
    "TNR811_1_03": ["Ce urmează? 5, 10, 15, 20, __", "Numără din 5 în 5.", ["24", "25", "30", "22"], "Counting by 5s: 5, 10, 15, 20, 25."],
    "TNR811_1_04": ["Cât este dublul lui 8?", "Dublu înseamnă ×2.", ["14", "16", "18", "10"], "Double 8 = 8 × 2 = 16."],
    "TNR811_1_05": ["Cât este 4 × 7?", "Gândește-te la 4 groups of 7.", ["24", "21", "28", "32"], "4 × 7 = 28."],
    "TNR811_1_06": ["Ce urmează? 3, 6, 9, 12, __", "Numără din 3 în 3.", ["13", "14", "15", "16"], "Counting by 3s: 3, 6, 9, 12, 15."],
    "TNR811_1_07": ["Cât este dublul lui 15?", "Dublu înseamnă multiply by 2.", ["25", "28", "30", "35"], "Double 15 = 15 × 2 = 30."],
    "TNR811_1_08": ["Cât este 5 × 8?", "Gândește-te la 5 groups of 8.", ["35", "45", "40", "48"], "5 × 8 = 40."],
    "TNR811_1_09": ["Numără din 4s: 4, 8, 12, __, 20. Cât este missing?", "Cât este 12 + 4?", ["14", "16", "15", "18"], "Counting by 4s: 4, 8, 12, 16, 20."],
    "TNR811_1_10": ["Cât este 3 × 9?", "Gândește-te la 3 groups of 9.", ["24", "27", "21", "29"], "3 × 9 = 27."],
    "TNR811_1_11": ["Cât este dublul lui 25?", "Dublu înseamnă ×2.", ["45", "50", "55", "40"], "Double 25 = 25 × 2 = 50."],
    "TNR811_1_12": ["Cât este 4 × 8?", "Gândește-te la 4 groups of 8.", ["28", "30", "32", "36"], "4 × 8 = 32."],
    "TNR811_1_13": ["Numără din 6s: 6, 12, 18, __, 30. Cât este missing?", "Cât este 18 + 6?", ["22", "26", "24", "20"], "Counting by 6s: 6, 12, 18, 24, 30."],
    "TNR811_1_14": ["Cât este 5 × 9?", "Gândește-te la 5 groups of 9.", ["40", "50", "45", "54"], "5 × 9 = 45."],
    "TNR811_1_15": ["Cât este dublul lui 12?", "Dublu înseamnă ×2.", ["22", "24", "20", "26"], "Double 12 = 12 × 2 = 24."],
    "TNR811_1_16": ["Cât este 3 × 7?", "Gândește-te la 3 groups of 7.", ["18", "24", "21", "28"], "3 × 7 = 21."],
    "TNR811_1_17": ["Numără din 3s: 3, 6, 9, 12, 15, __. Ce urmează?", "Adună 3 la fiecare pas.", ["16", "17", "18", "19"], "Counting by 3s: 3, 6, 9, 12, 15, 18."],
    "TNR811_1_18": ["Cât este 4 × 9?", "Gândește-te la 4 groups of 9.", ["32", "36", "40", "27"], "4 × 9 = 36."],
    "TNR811_1_19": ["Cât este dublul lui 35?", "Dublu înseamnă ×2.", ["60", "65", "70", "75"], "Double 35 = 35 × 2 = 70."],
    "TNR811_1_20": ["Cât este 5 × 7?", "Gândește-te la 5 groups of 7.", ["30", "35", "40", "42"], "5 × 7 = 35."],
    "TNR811_2_01": ["Cât este jumătate din 48?", "Jumătate înseamnă ÷2.", ["20", "22", "24", "28"], "Half of 48 = 48 ÷ 2 = 24."],
    "TNR811_2_02": ["Cât este triplul lui 9?", "Triplu înseamnă ×3.", ["18", "27", "24", "21"], "Triple 9 = 9 × 3 = 27."],
    "TNR811_2_03": ["Șir: 2, 4, 3, 6, 5, 10, 9, __. Regula alternează: double, apoi subtract 1. Ce urmează?", "9 vine după un pas de scădere. Ce operație urmează?", ["10", "18", "8", "12"], "Tiparul alternează ×2 și −1. După 9 we double: 9 × 2 = 18."],
    "TNR811_2_04": ["Cât este jumătate din 64?", "Jumătate înseamnă ÷2.", ["30", "34", "32", "36"], "Half of 64 = 64 ÷ 2 = 32."],
    "TNR811_2_05": ["Cât este triplul lui 12?", "Triplu înseamnă ×3.", ["24", "30", "36", "48"], "Triple 12 = 12 × 3 = 36."],
    "TNR811_2_06": ["Șir: 1, 3, 2, 6, 5, 15, 14, __. Regula alternează: ×3, apoi −1. Ce urmează?", "14 vine după ce ai scăzut 1. Ce operație urmează?", ["13", "28", "42", "15"], "Alternanță: ×3 și −1. După 14 we multiply: 14 × 3 = 42."],
    "TNR811_2_07": ["Cât este jumătate din 100?", "Jumătate înseamnă ÷2.", ["40", "50", "55", "45"], "Half of 100 = 100 ÷ 2 = 50."],
    "TNR811_2_08": ["Cât este triplul lui 15?", "Triplu înseamnă ×3.", ["30", "40", "45", "60"], "Triple 15 = 15 × 3 = 45."],
    "TNR811_2_09": ["Ce urmează? 80, 40, 20, __", "Fiecare număr se înjumătățește.", ["15", "10", "5", "12"], "Fiecare număr se împarte la 2: 80, 40, 20, 10."],
    "TNR811_2_10": ["Cât este jumătate din 36?", "Jumătate înseamnă ÷2.", ["16", "18", "20", "14"], "Half of 36 = 36 ÷ 2 = 18."],
    "TNR811_2_11": ["Cât este triplul lui 20?", "Triplu înseamnă ×3.", ["40", "50", "60", "80"], "Triple 20 = 20 × 3 = 60."],
    "TNR811_2_12": ["Șir: 1, 2, 4, 5, 10, 11, 22, __. Regula alternează: +1, apoi ×2. Ce urmează?", "22 vine după dublare. Ce operație urmează?", ["23", "24", "44", "32"], "Alternanță: +1 și ×2. După 22 adunăm 1: 22 + 1 = 23."],
    "TNR811_2_13": ["Cât este jumătate din 56?", "Jumătate înseamnă ÷2.", ["24", "26", "28", "30"], "Half of 56 = 56 ÷ 2 = 28."],
    "TNR811_2_14": ["Cât este triplul lui 8?", "Triplu înseamnă ×3.", ["16", "20", "24", "28"], "Triple 8 = 8 × 3 = 24."],
    "TNR811_2_15": ["Ce urmează? 96, 48, 24, 12, __", "Fiecare număr se înjumătățește.", ["8", "6", "10", "4"], "Fiecare număr se împarte la 2: 96, 48, 24, 12, 6."],
    "TNR811_2_16": ["Cât este jumătate din 72?", "Jumătate înseamnă ÷2.", ["32", "34", "36", "38"], "Half of 72 = 72 ÷ 2 = 36."],
    "TNR811_2_17": ["Cât este triplul lui 25?", "Triplu înseamnă ×3.", ["50", "65", "75", "100"], "Triple 25 = 25 × 3 = 75."],
    "TNR811_2_18": ["Șir: 5, 15, 10, 30, 25, 75, 70, __. Regula alternează: ×3, apoi −5. Ce urmează?", "70 vine după ce ai scăzut 5. Ce operație urmează?", ["65", "140", "210", "105"], "Alternanță: ×3 și −5. După 70 we multiply: 70 × 3 = 210."],
    "TNR811_2_19": ["Cât este jumătate din 84?", "Jumătate înseamnă ÷2.", ["38", "40", "42", "44"], "Half of 84 = 84 ÷ 2 = 42."],
    "TNR811_2_20": ["Cât este triplul lui 30?", "Triplu înseamnă ×3.", ["60", "90", "100", "120"], "Triple 30 = 30 × 3 = 90."],
    "TNR811_3_01": ["Ce urmează? 1, 3, 7, 15, 31, __", "Try ×2 apoi +1.", ["47", "62", "63", "60"], "Rule: ×2 apoi +1. 1→3, 3→7, 7→15, 15→31, 31→63."],
    "TNR811_3_02": ["Ce urmează? 2, 6, 18, 54, __", "Fiecare număr este ×3.", ["108", "162", "72", "60"], "Fiecare număr se înmulțește cu 3: 2, 6, 18, 54, 162."],
    "TNR811_3_03": ["Ce urmează? 100, 97, 91, 82, 70, __", "Uită-te la diferențe: −3, −6, −9, −12...", ["58", "55", "52", "60"], "Differences increase by 3: −3, −6, −9, −12, −15. So 70 − 15 = 55."],
    "TNR811_3_04": ["Ce urmează? 3, 4, 6, 10, 18, __", "Uită-te la diferențe: 1, 2, 4, 8... they double.", ["26", "34", "28", "36"], "Diferențele se dublează: +1, +2, +4, +8, +16. So 18 + 16 = 34."],
    "TNR811_3_05": ["Ce urmează? 2, 5, 11, 23, 47, __", "Try ×2 apoi +1.", ["94", "95", "93", "96"], "Rule: ×2 apoi +1. 2→5, 5→11, 11→23, 23→47, 47→95."],
    "TNR811_3_06": ["Ce urmează? 256, 128, 64, 32, __", "Fiecare număr se înjumătățește.", ["24", "16", "8", "20"], "Fiecare număr se împarte la 2: 256, 128, 64, 32, 16."],
    "TNR811_3_07": ["Ce urmează? 1, 4, 13, 40, __", "Try ×3 apoi +1.", ["80", "120", "121", "81"], "Rule: ×3 apoi +1. 1→4, 4→13, 13→40, 40→121."],
    "TNR811_3_08": ["Ce urmează? 50, 46, 40, 32, 22, __", "Differences increase: −4, −6, −8, −10...", ["10", "12", "14", "8"], "Differences increase by 2: −4, −6, −8, −10, −12. So 22 − 12 = 10."],
    "TNR811_3_09": ["Ce urmează? 3, 9, 27, 81, __", "Fiecare număr este ×3.", ["162", "243", "108", "100"], "Fiecare număr se înmulțește cu 3: 3, 9, 27, 81, 243."],
    "TNR811_3_10": ["Ce urmează? 2, 3, 5, 9, 17, __", "Diferențele se dublează: +1, +2, +4, +8...", ["25", "33", "34", "31"], "Diferențele se dublează: +1, +2, +4, +8, +16. So 17 + 16 = 33."],
    "TNR811_3_11": ["Ce urmează? 1, 5, 13, 29, __", "Try ×2 apoi +3.", ["57", "58", "61", "45"], "Rule: ×2 apoi +3. 1→5, 5→13, 13→29, 29→61."],
    "TNR811_3_12": ["Ce urmează? 200, 195, 185, 170, 150, __", "Differences increase: −5, −10, −15, −20...", ["130", "125", "120", "135"], "Differences increase by 5: −5, −10, −15, −20, −25. So 150 − 25 = 125."],
    "TNR811_3_13": ["Ce urmează? 4, 16, 64, 256, __", "Fiecare număr este ×4.", ["512", "1024", "768", "640"], "Fiecare număr este înmulțit cu 4: 4, 16, 64, 256, 1024."],
    "TNR811_3_14": ["Ce urmează? 1, 2, 6, 24, 120, __", "Înmulțește cu 2, apoi 3, apoi 4, apoi 5...", ["240", "600", "720", "360"], "×2, ×3, ×4, ×5, ×6. So 120 × 6 = 720. Acestea sunt called factorials."],
    "TNR811_3_15": ["Ce urmează? 5, 8, 14, 26, 50, __", "Diferențele se dublează: +3, +6, +12, +24...", ["74", "98", "76", "100"], "Diferențele se dublează: +3, +6, +12, +24, +48. So 50 + 48 = 98."],
    "TNR811_3_16": ["Ce urmează? 3, 10, 31, 94, __", "Try ×3 apoi +1.", ["188", "282", "283", "281"], "Rule: ×3 apoi +1. 3→10, 10→31, 31→94, 94→283."],
    "TNR811_3_17": ["Ce urmează? 80, 77, 71, 62, 50, __", "Differences increase: −3, −6, −9, −12...", ["35", "38", "40", "42"], "Differences increase by 3: −3, −6, −9, −12, −15. So 50 − 15 = 35."],
    "TNR811_3_18": ["Ce urmează? 1, 2, 4, 8, 16, 32, __", "Fiecare număr se dublează.", ["48", "60", "64", "36"], "Fiecare număr este ×2: 1, 2, 4, 8, 16, 32, 64."],
    "TNR811_3_19": ["Ce urmează? 2, 7, 22, 67, __", "Try ×3 apoi +1.", ["134", "200", "201", "202"], "Rule: ×3 apoi +1. 2→7, 7→22, 22→67, 67→202."],
    "TNR811_3_20": ["Ce urmează? 1000, 990, 970, 940, 900, __", "Differences increase: −10, −20, −30, −40...", ["860", "850", "840", "870"], "Differences increase by 10: −10, −20, −30, −40, −50. So 900 − 50 = 850."],
    "TLR811_1_01": ["Toți câinii sunt animale. Spot este un câine. Ce este Spot?", "Dacă Spot este câine și toți câinii sunt animale…", ["O plantă", "Un animal", "O pasăre", "Un pește"], "Toți câinii sunt animale. Spot este câine. Deci Spot este un animal."],
    "TLR811_1_02": ["Toate merele sunt fructe. Toate fructele sunt mâncare. Rezultă că toate merele sunt mâncare?", "Urmează lanțul: mere → fructe → mâncare.", ["Da", "Nu", "Doar unele", "Nu putem ști"], "Merele sunt fructe, iar fructele sunt mâncare. Deci toate merele sunt mâncare."],
    "TLR811_1_03": ["Tom este mai înalt decât Sam. Sam este mai înalt decât Ben. Cine este cel mai înalt?", "Pune-i în ordinea înălțimii.", ["Sam", "Ben", "Tom", "Sunt la fel"], "Tom > Sam > Ben. Tom este cel mai înalt."],
    "TLR811_1_04": ["Toate pisicile au coadă. Mustăți este o pisică. Are Mustăți coadă?", "Dacă toate pisicile au coadă și Mustăți este pisică…", ["Da", "Nu", "Poate", "Doar uneori"], "Toate pisicile au coadă. Mustăți este pisică. Deci Mustăți are coadă."],
    "TLR811_1_05": ["Ana este mai în vârstă decât Ben. Ben este mai în vârstă decât Cara. Cine este cea mai tânără?", "Ordonează-i de la cel mai bătrân la cel mai tânăr.", ["Ana", "Ben", "Cara", "Au aceeași vârstă"], "Ana > Ben > Cara ca vârstă. Cara este cea mai tânără."],
    "TLR811_1_06": ["Toate păsările au pene. O rândunică este o pasăre. Are rândunica pene?", "Dacă toate păsările au pene…", ["Nu", "Da", "Doar iarna", "Poate"], "Toate păsările au pene. Rândunica este pasăre. Deci are pene."],
    "TLR811_1_07": ["Roșu este mai mare decât Albastru. Albastru este mai mare decât Verde. Care este cel mai mic?", "Ordonează-le după mărime.", ["Roșu", "Albastru", "Verde", "Sunt egale"], "Roșu > Albastru > Verde. Verde este cel mai mic."],
    "TLR811_1_08": ["Toți peștii trăiesc în apă. Un pește-auriu este pește. Unde trăiește un pește-auriu?", "Dacă toți peștii trăiesc în apă…", ["Pe uscat", "În copaci", "În apă", "În cer"], "Toți peștii trăiesc în apă. Peștele-auriu este pește. Deci trăiește în apă."],
    "TLR811_1_09": ["Cartea A are mai multe pagini decât cartea B. Cartea B are mai multe pagini decât cartea C. Care are cele mai puține pagini?", "Ordonează cărțile după numărul de pagini.", ["Cartea A", "Cartea B", "Cartea C", "Sunt egale"], "A > B > C la pagini. Cartea C are cele mai puține pagini."],
    "TLR811_1_10": ["Toate pătratele au 4 laturi. Această formă este un pătrat. Câte laturi are?", "Dacă este pătrat…", ["3", "4", "5", "6"], "Toate pătratele au 4 laturi. Această formă este pătrat. Deci are 4 laturi."],
    "TLR811_1_11": ["Pizza este mai ieftină decât friptura. Friptura este mai ieftină decât homarul. Care este cel mai ieftin?", "Ordonează-le după preț.", ["Friptura", "Homarul", "Pizza", "Costă la fel"], "Pizza < Friptura < Homar la preț. Pizza este cea mai ieftină."],
    "TLR811_1_12": ["Toți trandafirii sunt flori. Toate florile sunt plante. Este trandafirul o plantă?", "Urmează lanțul: trandafiri → flori → plante.", ["Da", "Nu", "Poate", "Doar trandafirii roșii"], "Trandafirii sunt flori, iar florile sunt plante. Deci trandafirul este plantă."],
    "TLR811_1_13": ["Echipa A a marcat mai mult decât echipa B. Echipa B a marcat mai mult decât echipa C. Cine a marcat cel mai mult?", "Clasifică echipele după scor.", ["Echipa C", "Echipa B", "Echipa A", "Egalitate"], "A > B > C la scor. Echipa A a marcat cel mai mult."],
    "TLR811_1_14": ["Toate monedele sunt rotunde. Un penny este o monedă. Ce formă are un penny?", "Dacă toate monedele sunt rotunde…", ["Pătrat", "Triunghi", "Rotundă", "Ovală"], "Toate monedele sunt rotunde. Penny-ul este monedă. Deci este rotundă."],
    "TLR811_1_15": ["Mia aleargă mai repede decât Lily. Lily aleargă mai repede decât Zoe. Cine este cea mai lentă?", "Clasifică-le după viteză.", ["Mia", "Lily", "Zoe", "Sunt la fel"], "Mia > Lily > Zoe la viteză. Zoe este cea mai lentă."],
    "TLR811_1_16": ["Toate triunghiurile au 3 laturi. Această formă are 3 laturi. Poate fi triunghi?", "Triunghiurile au 3 laturi. Înseamnă asta neapărat că forma este triunghi?", ["Da, poate fi", "Nu, niciodată", "Doar dacă e mare", "Doar dacă e roșu"], "Toate triunghiurile au 3 laturi, iar această formă are 3 laturi, deci poate fi triunghi."],
    "TLR811_1_17": ["Un elefant este mai greu decât un cal. Un cal este mai greu decât un câine. Care este cel mai ușor?", "Clasifică-le după greutate.", ["Elefantul", "Calul", "Câinele", "Cântăresc la fel"], "Elefant > Cal > Câine la greutate. Câinele este cel mai ușor."],
    "TLR811_1_18": ["Toate creioanele pot scrie. Acesta este un creion. Poate scrie?", "Dacă toate creioanele pot scrie…", ["Da", "Nu", "Doar uneori", "Nu știm"], "Toate creioanele pot scrie. Acesta este creion. Deci poate scrie."],
    "TLR811_1_19": ["Cutia A este mai lată decât cutia B. Cutia B este mai lată decât cutia C. Care este cea mai lată?", "Clasifică cutiile după lățime.", ["Cutia C", "Cutia B", "Cutia A", "Sunt la fel"], "A > B > C la lățime. Cutia A este cea mai lată."],
    "TLR811_1_20": ["Toată înghețata este rece. Aceasta este înghețată. Este rece?", "Dacă toată înghețata este rece…", ["Nu", "Poate", "Da", "Doar iarna"], "Toată înghețata este rece. Aceasta este înghețată. Deci este rece."],
    "TLR811_2_01": ["Toată ciocolata este dulce. Această bomboană este dulce. Este SIGUR ciocolată?", "Numai pentru că toată ciocolata e dulce, înseamnă că tot ce e dulce e ciocolată?", ["Da, sigur", "Nu, nu neapărat", "Doar ciocolata neagră", "Mereu"], "Toată ciocolata e dulce, dar și alte lucruri pot fi dulci. Nu e neapărat ciocolată."],
    "TLR811_2_02": ["Anna este mai înaltă decât Ben. Ben este mai înalt decât Cara. Cara este mai înaltă decât Dan. Cine este a doua ca înălțime?", "Pune-i pe toți patru în ordinea înălțimii.", ["Anna", "Ben", "Cara", "Dan"], "Anna > Ben > Cara > Dan. Ben este al doilea ca înălțime."],
    "TLR811_2_03": ["Toate mașinile au roți. Acest vehicul are roți. Este SIGUR o mașină?", "Doar mașinile au roți?", ["Da", "Nu, nu neapărat", "Doar dacă e roșie", "Mereu"], "Multe vehicule au roți (biciclete, autobuze, camioane). Nu e neapărat mașină."],
    "TLR811_2_04": ["Roșu este mai mare decât Albastru. Albastru este mai mare decât Verde. Verde este mai mare decât Galben. Care este al treilea ca mărime?", "Clasifică-le pe toate patru după mărime.", ["Roșu", "Albastru", "Verde", "Galben"], "Roșu > Albastru > Verde > Galben. Verde este al treilea ca mărime."],
    "TLR811_2_05": ["Toate pătratele sunt dreptunghiuri. Această formă este dreptunghi. Este SIGUR pătrat?", "Toate pătratele sunt dreptunghiuri, dar toate dreptunghiurile sunt pătrate?", ["Da", "Nu, nu neapărat", "Doar dacă e mic", "Mereu"], "Toate pătratele sunt dreptunghiuri, dar nu toate dreptunghiurile sunt pătrate. Poate să nu fie pătrat."],
    "TLR811_2_06": ["Kim a luat 90 de puncte. Lee 85. Min 95. Pat 80. Cine a fost al doilea?", "Clasifică de la cel mai mare scor la cel mai mic.", ["Kim", "Lee", "Min", "Pat"], "Min (95) > Kim (90) > Lee (85) > Pat (80). Kim a fost al doilea."],
    "TLR811_2_07": ["Toți câinii latră. Un animal latră. Este SIGUR câine?", "Doar câinii latră?", ["Da, sigur", "Nu, nu neapărat", "Doar câinii mari latră", "Mereu"], "Și alte animale pot lătra (ex. focile). Nu e neapărat câine."],
    "TLR811_2_08": ["Cartea A are 200 de pagini. B are 150. C are 300. D are 250. Care este a treia ca lungime?", "Ordonează de la cele mai multe pagini la cele mai puține.", ["Cartea A", "Cartea B", "Cartea C", "Cartea D"], "C (300) > D (250) > A (200) > B (150). Cartea A este a treia ca lungime."],
    "TLR811_2_09": ["Toate numerele pare se împart exact la 2. Numărul 15 nu se împarte exact la 2. Ce putem spune despre 15?", "Dacă nu se împarte la 2, poate fi par?", ["Este par", "Nu este par", "Nu putem ști", "Poate fi par"], "Toate numerele pare se împart la 2. 15 nu se împarte la 2. Deci 15 nu este par."],
    "TLR811_2_10": ["Amy, Ben, Cat și Dan aleargă. Amy îl întrece pe Ben. Cat o întrece pe Amy. Dan o întrece pe Cat. Cine câștigă?", "Dacă Dan o întrece pe Cat, iar Cat pe Amy…", ["Amy", "Ben", "Cat", "Dan"], "Dan > Cat > Amy > Ben. Dan câștigă."],
    "TLR811_2_11": ["Toate bicicletele au 2 roți. Acest vehicul are 2 roți. Este SIGUR bicicletă?", "Doar bicicletele au 2 roți?", ["Da", "Nu, nu neapărat", "Doar mountain bike-uri", "Mereu"], "Și trotinetele, motocicletele au 2 roți. Nu e neapărat bicicletă."],
    "TLR811_2_12": ["Patru prieteni au scoruri diferite: 70, 80, 90, 100. James a luat mai mult de 80 dar mai puțin de 100. Care a fost scorul lui?", "Care scor e între 80 și 100?", ["70", "80", "90", "100"], "Singurul scor între 80 și 100 este 90."],
    "TLR811_2_13": ["Toți păianjenii au 8 picioare. Această creatură are 8 picioare. Este SIGUR păianjen?", "Doar păianjenii au 8 picioare?", ["Da", "Nu, nu neapărat", "Doar cei mari", "Mereu"], "Și scorpionii au 8 picioare. 8 picioare nu înseamnă neapărat păianjen."],
    "TLR811_2_14": ["Stejarul este mai înalt decât mesteacănul. Pinul este mai înalt decât stejarul. Ulmul este mai scund decât mesteacănul. Care copac este cel mai înalt?", "Ordonează toți cei patru copaci.", ["Stejarul", "Mesteacănul", "Pinul", "Ulmul"], "Pin > Stejar > Mesteacăn > Ulm. Pinul este cel mai înalt."],
    "TLR811_2_15": ["Toate planetele orbitează în jurul unei stele. Pământul orbitează o stea. Dovedește asta că Pământul este planetă?", "Doar planetele orbitează stele?", ["Da, o dovedește", "Nu, nu o dovedește", "Doar uneori", "Mereu"], "Și cometele, asteroizii orbitează stele. Orbita singură nu dovedește că e planetă."],
    "TLR811_2_16": ["Sam are mai multe abțibilduri decât Mia. Mia are mai multe decât Jo. Jo are mai multe decât Lee. Cine are cele mai puține?", "Ordonează-i.", ["Sam", "Mia", "Jo", "Lee"], "Sam > Mia > Jo > Lee. Lee are cele mai puține."],
    "TLR811_2_17": ["Dacă plouă, solul este ud. Solul este ud. Plouă SIGUR?", "Solul ar putea fi ud și din alte motive?", ["Da, sigur", "Nu, nu neapărat", "Doar vara", "Mereu"], "Cineva ar fi putut uda cu furtunul. Solul ud nu dovedește ploaia."],
    "TLR811_2_18": ["Pisica cântărește mai puțin decât câinele. Câinele mai puțin decât oaia. Oaia mai puțin decât vaca. Care animal cântărește cel mai mult?", "Clasifică după greutate.", ["Pisica", "Câinele", "Oaia", "Vaca"], "Pisică < Câine < Oaie < Vacă. Vaca cântărește cel mai mult."],
    "TLR811_2_19": ["Toate merele sunt fructe. Acesta NU este fruct. Poate fi măr?", "Dacă toate merele sunt fructe, iar acesta nu e fruct…", ["Da", "Nu, nu poate", "Poate", "Doar cele verzi"], "Toate merele sunt fructe. Dacă nu e fruct, nu poate fi măr."],
    "TLR811_2_20": ["Patru copii au vârstele 8, 9, 10, 11 ani. Kai este mai mare decât Zoe. Zoe decât Leo. Leo decât Ivy. Câți ani are Zoe?", "Kai e cel mai mare, apoi Zoe, Leo, Ivy.", ["8", "9", "10", "11"], "Kai=11, Zoe=10, Leo=9, Ivy=8. Zoe are 10 ani."],
    "TLR811_3_01": ["Dacă plouă, Tom ia umbrelă. Dacă ia umbrelă, rămâne uscat. Plouă. Va rămâne Tom uscat?", "Urmează lanțul: ploaie → umbrelă → uscat.", ["Da", "Nu", "Poate", "Doar dacă e frig"], "Ploaie → umbrelă → uscat. Plouă, deci Tom rămâne uscat."],
    "TLR811_3_02": ["Dacă A este adevărat, atunci B este adevărat. B NU este adevărat. Este A adevărat?", "Dacă A ar face mereu B adevărat, iar B e fals…", ["Da", "Nu", "Poate", "Nu putem ști"], "Dacă A ar fi adevărat, B ar trebui să fie adevărat. Dar B nu e. Deci A nu poate fi adevărat."],
    "TLR811_3_03": ["Astăzi este miercuri. Ce zi era acum 3 zile?", "Numără înapoi: marți, luni, duminică.", ["Luni", "Duminică", "Sâmbătă", "Marți"], "Miercuri −1 = marți, −2 = luni, −3 = duminică."],
    "TLR811_3_04": ["Dacă înveți, treci testul. Dacă treci testul, primești recompensa. Maya a învățat. Primește Maya recompensa?", "Urmează lanțul: învățare → trecere test → recompensă.", ["Da", "Nu", "Doar uneori", "Nu putem ști"], "Învățare → trecere → recompensă. Maya a învățat, deci primește recompensa."],
    "TLR811_3_05": ["Dacă Anna înoată, poartă ochelari de înot. Anna NU poartă ochelari. Înoată Anna?", "Dacă la înot poartă mereu ochelari, iar acum nu poartă…", ["Da", "Nu", "Poate", "Doar lunea"], "Dacă ar înota, ar purta ochelari. Nu poartă, deci nu înoată."],
    "TLR811_3_06": ["Astăzi este 28 martie. Ce dată este peste 5 zile?", "Martie are 31 de zile. Numără înainte de la 28.", ["33 martie", "1 aprilie", "2 aprilie", "3 aprilie"], "Martie are 31 zile. 28 + 5 = 33. 33 − 31 = 2. Deci este 2 aprilie."],
    "TLR811_3_07": ["Dacă Max mănâncă tort, i se face rău. Max NU i se face rău. A mâncat Max tort?", "Dacă tortul îi face mereu rău, iar acum nu i se face…", ["Da", "Nu", "Poate", "Doar tort de ciocolată"], "Dacă ar fi mâncat tort, i s-ar face rău. Nu i se face, deci nu a mâncat."],
    "TLR811_3_08": ["Dacă A duce la B, B la C, C la D. Se întâmplă A. Se întâmplă D?", "Urmează lanțul de la A la D.", ["Da", "Nu", "Doar uneori", "Nu putem ști"], "A → B → C → D. Dacă A, atunci și D."],
    "TLR811_3_09": ["Este octombrie. Câte luni până în martie (numărând înainte)?", "Numără: noiembrie, decembrie, ianuarie, februarie, martie.", ["4", "5", "6", "3"], "Nov (1), dec (2), ian (3), feb (4), mar (5). Sunt 5 luni."],
    "TLR811_3_10": ["Dacă o formă are 4 laturi egale și 4 unghiuri drepte, este pătrat. Această formă NU are 4 laturi egale. Sigur NU este pătrat?", "Poate fi pătrat fără 4 laturi egale?", ["Da, nu e pătrat", "Nu, tot ar putea fi pătrat", "Poate", "Doar dacă e mare"], "Pătratul trebuie să aibă 4 laturi egale. Dacă nu le are, nu e pătrat."],
    "TLR811_3_11": ["Dacă apeși butonul, lumina se aprinde. Dacă lumina se aprinde, sună clopoțelul. Ai apăsat butonul. Ce se întâmplă?", "Urmează lanțul: buton → lumină → clopoțel.", ["Nimic", "Doar lumina", "Sună clopoțelul", "Butonul se strică"], "Buton → lumină → clopoțel. Ai apăsat, deci sună clopoțelul."],
    "TLR811_3_12": ["Astăzi este vineri. Ce zi va fi peste 10 zile?", "10 = 7 + 3. O săptămână întreagă plus 3 zile.", ["Duminică", "Luni", "Marți", "Miercuri"], "10 zile = 1 săptămână + 3 zile. Vineri + 3 = luni."],
    "TLR811_3_13": ["Toți elevii din clasa A joacă fotbal. Tom NU joacă fotbal. Este Tom în clasa A?", "Dacă toți din A joacă fotbal, iar Tom nu…", ["Da", "Nu", "Poate", "Doar în weekend"], "Toți din A joacă fotbal. Tom nu joacă, deci nu e în clasa A."],
    "TLR811_3_14": ["Dacă ninge, școala e închisă. Dacă școala e închisă, copiii se joacă afară. NU a nins. Putem fi SIGURI că copiii NU se joacă afară?", "Școala s-ar putea închide din alt motiv?", ["Da, suntem siguri", "Nu, nu putem fi siguri", "Doar vara", "Mereu"], "Școala se poate închide și altfel (sărbători, reparații). Copiii tot s-ar putea juca afară."],
    "TLR811_3_15": ["Astăzi este 30 noiembrie. Ce dată este peste 3 zile?", "Noiembrie are 30 zile; ce urmează după 30 noiembrie?", ["33 noiembrie", "1 decembrie", "2 decembrie", "3 decembrie"], "Noiembrie are 30 zile. 30 nov +1 = 1 dec, +2 = 2 dec, +3 = 3 dec."],
    "TLR811_3_16": ["X este mai mare decât Y. Y decât Z. Z decât W. W decât V. Care este cel mai mare?", "Cine e în vârful lanțului?", ["V", "W", "Y", "X"], "X > Y > Z > W > V. X este cel mai mare."],
    "TLR811_3_17": ["Toți peștii pot înota. Ceva nu poate înota. Este pește?", "Dacă toți peștii înoată, iar acest lucru nu…", ["Da", "Nu", "Poate", "Doar peștii mici"], "Toți peștii înoată. Dacă nu poate înota, nu e pește."],
    "TLR811_3_18": ["Astăzi este marți. Ce zi va fi peste 25 zile?", "25 ÷ 7 = 3 săptămâni și 4 zile în plus.", ["Vineri", "Sâmbătă", "Duminică", "Luni"], "25 = 3 săptămâni + 4 zile. Marți + 4 = sâmbătă."],
    "TLR811_3_19": ["Dacă A e adevărat, B trebuie să fie adevărat. Dacă B e adevărat, C trebuie să fie adevărat. C NU este adevărat. Este A adevărat?", "Lucrează invers: dacă C e fals, ce e cu B? Apoi cu A?", ["Da", "Nu", "Poate", "Nu putem ști"], "Dacă A → B → C. C e fals, deci B e fals, deci A e fals."],
    "TLR811_3_20": ["Orice pisică e păroasă. Orice lucru păros e moale. Orice lucru moale e plăcut de îmbrățișat. Mustăți e pisică. E plăcut de îmbrățișat Mustăți?", "Urmează lanțul: pisică → păros → moale → plăcut de îmbrățișat.", ["Da", "Nu", "Poate", "Doar pisoii"], "Pisică → păros → moale → plăcut. Mustăți e pisică, deci e plăcut de îmbrățișat."],
    "TSR811_1_01": ["Câte fețe are un cub?", "Gândește-te la un zar — numără fețele plane.", ["4", "6", "8", "12"], "Un cub are 6 fețe plane."],
    "TSR811_1_02": ["Câte muchii are un cub?", "O muchie e unde se întâlnesc două fețe. Numără toate muchiile.", ["6", "8", "10", "12"], "Un cub are 12 muchii."],
    "TSR811_1_03": ["Câte vârfuri (colțuri) are un cub?", "Un vârf e punctul unde se întâlnesc muchiile.", ["4", "6", "8", "12"], "Un cub are 8 vârfuri (colțuri)."],
    "TSR811_1_04": ["Ce formă are fiecare față of a cube?", "Toate fețele cubului au aceeași formă.", ["Triunghi", "Dreptunghi", "Pătrat", "Cerc"], "Fiecare față of a cube is a square."],
    "TSR811_1_05": ["Câte fețe are o cutie dreptunghică (cuboid)?", "Gândește-te la a shoebox. Numără fețe plane.", ["4", "5", "6", "8"], "Un cuboid (cutie dreptunghică) are 6 fețe."],
    "TSR811_1_06": ["Câte fețe plane are o sferă?", "O sferă e ca o minge.", ["0", "1", "2", "4"], "O sferă are 0 fețe plane. E complet rotunjită."],
    "TSR811_1_07": ["Câte fețe plane are un cilindru?", "Gândește-te la a tin can. Ce părți plate are?", ["0", "1", "2", "3"], "Un cilindru are 2 fețe plane (cercul de sus și cercul de jos)."],
    "TSR811_1_08": ["Ce formă 3D are 6 fețe pătrate, toate la fel?", "Toate fețele sunt pătrate identice.", ["Cuboid", "Cube", "Prism", "Pyramid"], "Un cub are 6 fețe pătrate identice."],
    "TSR811_1_09": ["Câte fețe plane are un con?", "Gândește-te la un cornet de înghețată. Are o singură bază plată.", ["0", "1", "2", "3"], "Un con are 1 față plată (baza circulară)."],
    "TSR811_1_10": ["Câte muchii are o piramidă triunghiulară (tetraedru)?", "Are 4 fețe triunghiulare. Numără unde se întâlnesc triunghiurile.", ["4", "5", "6", "8"], "O piramidă triunghiulară (tetraedru) are 6 muchii."],
    "TSR811_1_11": ["Dacă  look at a cube from directly in front, ce formă vezi?", "Vezi o față a cubului frontal.", ["Triunghi", "Cerc", "Pătrat", "Dreptunghi"], "Looking directly at one face of a cube, you see a square."],
    "TSR811_1_12": ["Câte fețe are o prismă triunghiulară?", "Gândește-te la a Toblerone box — 2 triangles și some rectangles.", ["3", "4", "5", "6"], "O prismă triunghiulară has 5 fețe: 2 triangles și 3 rectangles."],
    "TSR811_1_13": ["Câte vârfuri are o piramidă triunghiulară (tetraedru)?", "Numără colțurile ascuțite.", ["3", "4", "5", "6"], "O piramidă triunghiulară are 4 vârfuri."],
    "TSR811_1_14": ["Ce formă are baza unui con?", "Baza plată a unui con este…", ["Pătrat", "Triunghi", "Cerc", "Oval"], "The base of a cone is a circle."],
    "TSR811_1_15": ["Câte muchii are un cuboid?", "Un cuboid e ca un cub, dar cu fețe dreptunghiulare. Numără muchiile.", ["8", "10", "12", "14"], "Un cuboid are 12 muchii, la fel ca un cub."],
    "TSR811_1_16": ["Câte fețe are o piramidă cu baza pătrată?", "Are bază pătrată și fețe triunghiulare laterale.", ["4", "5", "6", "8"], "O piramidă cu baza pătrată are 5 fețe: 1 bază pătrată și 4 triunghiuri."],
    "TSR811_1_17": ["Dacă suprapui 2 cuburi unul peste altul, forma combinată seamănă cel mai mult cu un…", "Two cubes stacked make a taller shape.", ["Cube", "Sphere", "Cuboid", "Cylinder"], "Two cubes stacked form a cuboid (rectangular box)."],
    "TSR811_1_18": ["Câte vârfuri are un cuboid?", "Numără toate colțurile of a rectangular box.", ["4", "6", "8", "10"], "Un cuboid are 8 vârfuri, la fel ca un cub."],
    "TSR811_1_19": ["Câte curved surfețe are o sferă?", "O sferă is perfectly round all over.", ["0", "1", "2", "4"], "O sferă has 1 curved surface."],
    "TSR811_1_20": ["Câte fețe are o prismă hexagonală?", "Are 2 capete hexagonale și fețe dreptunghiulare laterale. Hexagonul are 6 laturi.", ["6", "7", "8", "10"], "O prismă hexagonală are 8 fețe: 2 hexagoane + 6 dreptunghiuri."],
    "TSR811_2_01": ["Dacă tai un cub exact pe jumătate, paralel cu una dintre fețe, ce formă are secțiunea?", "Tai drept, ca și cum ai tăia pâinea.", ["Triunghi", "Cerc", "Pătrat", "Dreptunghi"], "Tăind cubul paralel cu o față obții o secțiune în formă de pătrat."],
    "TSR811_2_02": ["8 cuburi mici formează un cub 2×2×2. Câte cuburi mici sunt complet ascunse (fără nicio față la vedere)?", "În aranjamentul 2×2×2, fiecare cub este la exterior.", ["0", "1", "2", "4"], "În cubul 2×2×2, fiecare cub mic este la colț, cu fețe vizibile. Niciunul nu e ascuns."],
    "TSR811_2_03": ["Câte muchii are o prismă triunghiulară?", "3 muchii on top triangle + 3 on bottom + 3 connecting them.", ["6", "8", "9", "12"], "O prismă triunghiulară has 9 muchii: 3 + 3 + 3."],
    "TSR811_2_04": ["Aliniezi 3 cuburi unul după altul, față în față. Câte fețe ale cuburilor mici sunt ascunse (ating un alt cub)?", "Unde se ating cuburile, 2 fețe sunt ascunse la fiecare îmbinare.", ["2", "3", "4", "6"], "Sunt 2 îmbinări. Fiecare ascunde 2 fețe. Total fețe ascunse: 2 × 2 = 4."],
    "TSR811_2_05": ["Câte muchii are o piramidă cu baza pătrată?", "4 muchii la bază + 4 spre vârf.", ["5", "6", "8", "10"], "O piramidă cu baza pătrată are 8 muchii: 4 la bază + 4 laterale."],
    "TSR811_2_06": ["Dacă tai un cilindru la mijloc (perpendicular pe înălțime), ce formă are secțiunea?", "Tai ca pe un butuc, perpendicular pe axă.", ["Pătrat", "Dreptunghi", "Cerc", "Oval"], "Tăind cilindrul perpendicular pe înălțime obții un cerc."],
    "TSR811_2_07": ["27 cuburi mici formează un cub 3×3×3. Câte cuburi mici au cel puțin o față vizibilă la exterior?", "Doar cubul din centrul exact este complet ascuns.", ["24", "25", "26", "27"], "Doar 1 cub (cel din centru) e ascuns. 27 − 1 = 26 cuburi au cel puțin o față vizibilă."],
    "TSR811_2_08": ["Câte fețe are o prismă pentagonală?", "2 capete pentagonale + fețe dreptunghiulare. Pentagonul are 5 laturi.", ["5", "6", "7", "8"], "O prismă pentagonală are 7 fețe: 2 pentagoane + 5 dreptunghiuri."],
    "TSR811_2_09": ["Câte vârfuri are o piramidă cu baza pătrată?", "4 colțuri la bază + 1 punct în vârf.", ["4", "5", "6", "8"], "O piramidă cu baza pătrată are 5 vârfuri: 4 la bază + 1 vârf."],
    "TSR811_2_10": ["4 cuburi sunt așezate într-un pătrat 2×2, un singur strat. Câte fețe se văd de sus?", "Fiecare cub arată 1 față în sus.", ["2", "3", "4", "8"], "Fiecare din cele 4 cuburi arată 1 față sus. Total = 4 fețe sus."],
    "TSR811_2_11": ["Câte fețe are o piramidă hexagonală?", "1 bază hexagonală + fețe triunghiulare laterale. Hexagonul are 6 laturi.", ["6", "7", "8", "9"], "O piramidă hexagonală are 7 fețe: 1 hexagon + 6 triunghiuri."],
    "TSR811_2_12": ["Dacă tai un cub de la o muchie la muchia opusă (diagonal prin mijloc), secțiunea este un…", "Tăietura e diagonală dar rămâne plană.", ["Triunghi", "Pătrat", "Dreptunghi", "Cerc"], "Tăind de la o muchie la cea opusă obții o secțiune dreptunghiulară."],
    "TSR811_2_13": ["Câte fețe are o piramidă triunghiulară (tetraedru)?", "Toate fețele sale sunt triunghiuri.", ["3", "4", "5", "6"], "O piramidă triunghiulară are 4 fețe triunghiulare."],
    "TSR811_2_14": ["8 cuburi formează un cub 2×2×2. Câte fețe ale cuburilor mici se văd la exteriorul cubului mare?", "Cubul mare are 6 fețe, fiecare formată din 4 fețe mici.", ["16", "20", "24", "32"], "6 fețe mari × 4 fețe mici fiecare = 24 fețe mici vizibile."],
    "TSR811_2_15": ["Câte vârfuri are o piramidă cu baza pentagonală?", "5 colțuri la bază + 1 punct în vârf.", ["5", "6", "7", "10"], "O piramidă pentagonală are 6 vârfuri: 5 la bază + 1 vârf."],
    "TSR811_2_16": ["Câte muchii are o prismă hexagonală?", "6 sus + 6 jos + 6 care le leagă.", ["12", "14", "16", "18"], "O prismă hexagonală are 18 muchii: 6 + 6 + 6."],
    "TSR811_2_17": ["Scoți un cub de la colț dintr-un aranjament 2×2×2. Câte cuburi mici rămân?", "Ai 8 cuburi mici și scoți 1.", ["5", "6", "7", "4"], "8 − 1 = 7 cuburi rămase."],
    "TSR811_2_18": ["Câte vârfuri are o prismă triunghiulară?", "3 corners on each triangular end.", ["4", "5", "6", "8"], "O prismă triunghiulară has 6 vârfuri: 3 on each triangle."],
    "TSR811_2_19": ["Dacă vopsești toate fețele unui cub 2×2×2 și îl desfaci, câte cuburi mici au exact 3 fețe vopsite?", "În cubul 2×2×2, fiecare cub mic e la colț.", ["4", "6", "8", "0"], "Toate cele 8 cuburi din 2×2×2 sunt la colț, deci toate 8 au exact 3 fețe vopsite."],
    "TSR811_2_20": ["Câte fețe are o prismă octogonală?", "2 capete octogonale + fețe dreptunghiulare. Octogonul are 8 laturi.", ["8", "10", "12", "16"], "O prismă octogonală are 10 fețe: 2 octogoane + 8 dreptunghiuri."],
    "TSR811_3_01": ["Desfășurata unui cub (versiunea desfășurată) este format din câte pătrate?", "Fiecare față a cubului devine un pătrat în desfășurată.", ["4", "5", "6", "8"], "Un cub are 6 fețe, deci desfășurata are 6 pătrate."],
    "TSR811_3_02": ["Într-un cub 3×3×3 din 27 cuburi mici, câte cuburi sunt complet ascunse (fără față la vedere)?", "Doar cubul din centrul exact nu are față spre exterior.", ["0", "1", "4", "8"], "Doar 1 cub, cel din centrul exact, e complet ascuns."],
    "TSR811_3_03": ["Când pliezi o desfășurată în cruce (ca un plus din 6 pătrate), ce formă 3D obții?", "Desfășurata în cruce e una dintre cele mai uzuale pentru o formă foarte cunoscută.", ["Pyramid", "Cuboid", "Cube", "Prism"], "O desfășurată în cruce din 6 pătrate se pliază într-un cub."],
    "TSR811_3_04": ["Într-un cub 3×3×3, câte cuburi mici au exact 3 fețe vizibile?", "Cuburile de la colț au 3 fețe vizibile. Câte colțuri are un cub?", ["4", "6", "8", "12"], "Un cub are 8 colțuri. Fiecare cub de colț are exact 3 fețe vizibile."],
    "TSR811_3_05": ["Dacă lipești 2 cuburi pe o față, câte fețe are forma nouă în total?", "Fiecare cub are 6 fețe, dar 2 sunt ascunse unde sunt lipite.", ["8", "10", "11", "12"], "6 + 6 = 12 total fețe. Scade 2 hidden fețe: 12 − 2 = 10."],
    "TSR811_3_06": ["Într-un cub 3×3×3, câte cuburi mici au exact 2 fețe vizibile?", "Cuburile de pe muchii (nu colțurile) au 2 fețe vizibile. Câte muchii are un cub?", ["6", "8", "12", "24"], "Un cub are 12 muchii. Pe fiecare muchie e 1 cub care nu e colț. 12 × 1 = 12 cuburi cu 2 fețe."],
    "TSR811_3_07": ["Dacă tai un cub cu o singură tăietură dreaptă, câte piese maxim obții?", "O singură tăietură împarte în cel mult 2 părți.", ["2", "3", "4", "6"], "O tăietură dreaptă prin orice formă dă cel mult 2 piese."],
    "TSR811_3_08": ["Într-un cub 3×3×3, câte cuburi mici au exact 1 față vizibilă?", "Cuburile din centrul fiecărei fețe au 1 față vizibilă. Un cub are 6 fețe.", ["4", "6", "8", "12"], "Pe fiecare din cele 6 fețe e 1 cub central. 6 × 1 = 6 cuburi cu exact 1 față."],
    "TSR811_3_09": ["O desfășurată pentru o piramidă cu baza pătrată e formată din câte forme?", "Numără baza și fețele triunghiulare.", ["4", "5", "6", "8"], "Desfășurata are 5 forme: 1 pătrat (bază) + 4 triunghiuri (laturi)."],
    "TSR811_3_10": ["Dacă lipești 3 cuburi în șir (față în față), câte fețe are forma nouă?", "3 cuburi = 18 fețe în total. Sunt 2 îmbinări, fiecare ascunde 2 fețe.", ["12", "14", "16", "18"], "3 × 6 = 18 fețe. 2 îmbinări × 2 fețe ascunse = 4 ascunse. 18 − 4 = 14."],
    "TSR811_3_11": ["Într-un cub 4×4×4 (64 cuburi mici), câte cuburi mici sunt la suprafață?", "Total cuburi minus cele din interior. Interiorul e 2×2×2.", ["48", "52", "56", "60"], "Interior = 2×2×2 = 8 cuburi. Exterior = 64 − 8 = 56."],
    "TSR811_3_12": ["Dacă vopsești un cub 3×3×3 și îl desfaci în cuburi mici, câte nu au deloc vopsea?", "Doar cubul din centrul exact nu are față vopsită.", ["0", "1", "4", "8"], "Doar cubul din centru nu atinge exteriorul, deci nu are vopsea."],
    "TSR811_3_13": ["A net for a triangular prism has how many shapes?", "2 triangular ends + rectangular sides.", ["3", "4", "5", "6"], "The net has 5 shapes: 2 triangles + 3 rectangles."],
    "TSR811_3_14": ["Dacă vopsești un cub 2×2×2 și îl împarți în 8 cuburi mici, câte au exact 3 fețe vopsite?", "În 2×2×2, fiecare cub e la colț.", ["4", "6", "8", "2"], "Toate 8 sunt la colț, deci toate au exact 3 fețe vopsite."],
    "TSR811_3_15": ["Privind un cub dinspre un colț, câte fețe vezi cel mult în același timp?", "Dinspre un colț vezi fețele care se întâlnesc acolo.", ["1", "2", "3", "4"], "Dintr-un colț al cubului vezi cel mult 3 fețe."],
    "TSR811_3_16": ["Într-un cub 3×3×3, numărul total de fețe mici vizibile la exterior este…?", "Cubul mare are 6 fețe, fiecare din 9 fețe mici.", ["36", "48", "54", "27"], "6 fețe mari × 9 fețe mici = 54 fețe mici vizibile."],
    "TSR811_3_17": ["Dacă lipești 2 cuburi alături și pui al treilea deasupra unuia (formă de L), câte fețe are forma?", "2 cuburi lipite = 10 fețe. Al treilea deasupra ascunde încă 2 fețe.", ["12", "14", "16", "18"], "2 cuburi lipite = 10 fețe. Al treilea cub: 10 + 6 − 2 = 14 fețe."],
    "TSR811_3_18": ["Câte small cubes are needed to build a 4×4×4 cube?", "Multiply 4 × 4 × 4.", ["16", "32", "48", "64"], "4 × 4 × 4 = 64 small cubes."],
    "TSR811_3_19": ["Într-un cub 3×3×3, câte cuburi mici au o față comună cu cubul din centru?", "Cubul central e atins de cuburi sus, jos, stânga, dreapta, față, spate.", ["4", "6", "8", "12"], "Cubul central e atins din 6 direcții: sus, jos, stânga, dreapta, față, spate."],
    "TSR811_3_20": ["Dacă lipești 6 cuburi într-un dreptunghi plat 2×3×1, câte fețe are forma?", "6 cuburi = 36 fețe. Numără îmbinările din interior care ascund fețe.", ["18", "20", "22", "24"], "6 × 6 = 36 fețe. Sunt 7 îmbinări interioare (4 orizontale + 3 verticale), fiecare ascunde 2 fețe: 36 − 14 = 22."],
    "TMP811_1_01": ["Un fermier are 25 de oi. Toate fug, în afară de 9. Câte oi rămân?", "«Toate în afară de 9» înseamnă că 9 nu au fugit.", ["16", "9", "25", "0"], "«Toate în afară de 9 fug» înseamnă că 9 rămân. Răspunsul este 9."],
    "TMP811_1_02": ["3 prieteni împart în mod egal 12 fursecuri. Câte primește fiecare?", "Împarte 12 la 3.", ["3", "4", "5", "6"], "12 ÷ 3 = 4 fursecuri fiecăruia."],
    "TMP811_1_03": ["Un magazin vinde mere cu £2 bucata. Cât costă 5 mere?", "Înmulțește prețul unitar cu numărul de mere.", ["£7", "£8", "£10", "£12"], "5 × £2 = £10."],
    "TMP811_1_04": ["Câte luni din an au 28 de zile?", "Gândește-te bine — oare doar unele luni ajung la 28 de zile?", ["1", "6", "12", "2"], "Toate cele 12 luni au cel puțin 28 de zile!"],
    "TMP811_1_05": ["O carte are 6 capitole, fiecare cu 10 pagini. Câte pagini are în total?", "Înmulțește numărul de capitole cu paginile pe capitol.", ["16", "50", "60", "66"], "6 × 10 = 60 pagini."],
    "TMP811_1_06": ["Ai 3 cutii, în fiecare câte 4 mingi. Câte mingi ai în total?", "Înmulțește cutiile cu mingile din fiecare cutie.", ["7", "9", "12", "15"], "3 × 4 = 12 mingi."],
    "TMP811_1_07": ["Într-o cursă, îl depășești pe cel clasat pe locul 2. Pe ce loc ești acum?", "Dacă îl depășești pe cel de pe locul 2, îi iei locul.", ["Locul 1", "Locul 2", "Locul 3", "Locul 4"], "Ești pe locul 2. L-ai depășit pe al doilea, nu pe primul."],
    "TMP811_1_08": ["Un brutar face 5 torturi pe oră. Câte torturi face în 4 ore?", "Înmulțește torturile pe oră cu numărul de ore.", ["9", "15", "20", "25"], "5 × 4 = 20 torturi."],
    "TMP811_1_09": ["Tom are 8 jucării. Primește încă 3 de ziua lui. Câte are acum?", "Adună jucăriile noi la ce avea deja.", ["5", "10", "11", "12"], "8 + 3 = 11 jucării."],
    "TMP811_1_10": ["Ce cântărește mai mult: 1 kg de pene sau 1 kg de pietre?", "Uită-te la greutate — ambele sunt 1 kg.", ["Penele", "Pietrele", "La fel", "Depinde"], "Ambele cântăresc 1 kg, deci la fel!"],
    "TMP811_1_11": ["Un păianjen are 8 picioare. Câte picioare au 3 păianjeni?", "Înmulțește picioarele unui păianjen cu numărul de păianjeni.", ["16", "20", "24", "28"], "3 × 8 = 24 picioare."],
    "TMP811_1_12": ["Ai 20 de bomboane și mănânci câte 3 pe zi. După 4 zile, câte îți rămân?", "Calculează mai întâi câte ai mâncat în total.", ["5", "8", "10", "12"], "4 × 3 = 12 mâncate. 20 − 12 = 8 rămase."],
    "TMP811_1_13": ["Câte laturi are un cerc?", "O latură e o muchie dreaptă. Are cercul muchii drepte?", ["0", "1", "2", "4"], "Un cerc are 0 laturi drepte."],
    "TMP811_1_14": ["O mașină are 4 roți. Câte roți au 5 mașini?", "Înmulțește roțile unei mașini cu numărul de mașini.", ["9", "15", "16", "20"], "5 × 4 = 20 roți."],
    "TMP811_1_15": ["O duzină de ouă înseamnă 12. Câte ouă sunt jumătate de duzină?", "Jumătate din 12 este…", ["4", "5", "6", "8"], "Jumătate de duzină = 12 ÷ 2 = 6."],
    "TMP811_1_16": ["Dacă astăzi îți sărbătorești a 9-a aniversare, câte aniversări ai avut până acum?", "Prima aniversare a fost când ai împlinit 1 an; acum e a 9-a.", ["8", "9", "10", "1"], "A 9-a aniversare înseamnă că ai sărbătorit de 9 ori."],
    "TMP811_1_17": ["O săptămână are 7 zile. Câte zile sunt în 3 săptămâni?", "Înmulțește zilele dintr-o săptămână cu numărul de săptămâni.", ["10", "14", "21", "28"], "3 × 7 = 21 zile."],
    "TMP811_1_18": ["Ai £5,00 și cheltuiești £1,50. Cât îți rămâne?", "Scade ce ai cheltuit.", ["£2.50", "£3.00", "£3.50", "£4.00"], "£5,00 − £1,50 = £3,50."],
    "TMP811_1_19": ["4 prieteni au fiecare câte 6 bile. Câte bile au împreună?", "Înmulțește numărul de prieteni cu bilele fiecăruia.", ["10", "18", "20", "24"], "4 × 6 = 24 bile."],
    "TMP811_1_20": ["Câte minute are jumătate de oră?", "O oră are 60 de minute.", ["20", "25", "30", "45"], "Jumătate din 60 minute = 30 minute."],
    "TMP811_2_01": ["Un melc merge 3 cm într-un minut. Cât parcurge în 10 minute?", "Înmulțește viteza cu timpul.", ["13 cm", "30 cm", "33 cm", "300 cm"], "3 × 10 = 30 cm."],
    "TMP811_2_02": ["Într-un pătrat magic, fiecare rând însumează 15. Primul rând este: 2, ?, 6. Care e numărul lipsă?", "2 + ? + 6 = 15.", ["5", "6", "7", "8"], "2 + ? + 6 = 15, deci ? = 15 − 2 − 6 = 7."],
    "TMP811_2_03": ["24 de bomboane se împart în mod egal la 6 copii. Câte primește fiecare?", "Împarte bomboanele la numărul de copii.", ["3", "4", "5", "6"], "24 ÷ 6 = 4 bomboane fiecăruia."],
    "TMP811_2_04": ["Un robinet umple o găleată în 10 minute. Câte găleți poate umple într-o oră?", "1 oră = 60 minute.", ["4", "5", "6", "10"], "60 ÷ 10 = 6 găleți."],
    "TMP811_2_05": ["Într-un pătrat magic (suma 15), un rând este: 6, 5, ?. Care e numărul lipsă?", "6 + 5 + ? = 15.", ["3", "4", "5", "6"], "6 + 5 + ? = 15, deci ? = 15 − 6 − 5 = 4."],
    "TMP811_2_06": ["O bicicletă merge 12 km pe oră. Cât parcurge în 3 ore?", "Înmulțește viteza cu timpul.", ["15 km", "24 km", "36 km", "48 km"], "12 × 3 = 36 km."],
    "TMP811_2_07": ["3 prieteni găsesc £30 și îi împart în mod egal. Cât primește fiecare?", "Împarte £30 la 3.", ["£5", "£10", "£12", "£15"], "£30 ÷ 3 = £10 fiecare."],
    "TMP811_2_08": ["O fabrică face 50 de jucării pe zi. Câte face în 5 zile?", "Înmulțește jucăriile pe zi cu numărul de zile.", ["55", "100", "200", "250"], "50 × 5 = 250 jucării."],
    "TMP811_2_09": ["Într-un pătrat magic (suma 15), un rând este: 8, 3, ?. Care e numărul lipsă?", "8 + 3 + ? = 15.", ["3", "4", "5", "6"], "8 + 3 + ? = 15, deci ? = 15 − 8 − 3 = 4."],
    "TMP811_2_10": ["Cumperi 3 produse la £4,50 bucata. Cât plătești în total?", "Înmulțește prețul cu cantitatea.", ["£12.00", "£13.50", "£14.50", "£15.00"], "3 × £4,50 = £13,50."],
    "TMP811_2_11": ["Un tren merge 60 km pe oră. Cât parcurge în 2 ore?", "Înmulțește viteza cu timpul.", ["62 km", "90 km", "100 km", "120 km"], "60 × 2 = 120 km."],
    "TMP811_2_12": ["36 de mere se pun în cutii de câte 9. Câte cutii sunt necesare?", "Împarte 36 la 9.", ["3", "4", "5", "6"], "36 ÷ 9 = 4 cutii."],
    "TMP811_2_13": ["Într-un pătrat magic (suma 15), un rând este: 8, 1, ?. Care e numărul lipsă?", "8 + 1 + ? = 15.", ["4", "5", "6", "7"], "8 + 1 + ? = 15, deci ? = 15 − 8 − 1 = 6."],
    "TMP811_2_14": ["Ai £20. O carte costă £3,50. Câte cărți îți permiți să cumperi?", "Scade repetat £3,50 până nu mai poți.", ["4", "5", "6", "7"], "5 × £3,50 = £17,50 (ajunge). 6 × £3,50 = £21,00 (prea mult). Poți cumpăra 5."],
    "TMP811_2_15": ["Un furtun de grădină umple 2 litri pe minut. Câți litri în 15 minute?", "Înmulțește debitul cu timpul.", ["17", "25", "30", "32"], "2 × 15 = 30 litri."],
    "TMP811_2_16": ["5 copii împart în mod egal 35 de abțibilduri. Câte primește fiecare?", "Împarte 35 la 5.", ["5", "6", "7", "8"], "35 ÷ 5 = 7 abțibilduri fiecăruia."],
    "TMP811_2_17": ["Într-un pătrat magic (suma 15), un rând este: 4, 9, ?. Care e numărul lipsă?", "4 + 9 + ? = 15.", ["1", "2", "3", "4"], "4 + 9 + ? = 15, deci ? = 15 − 4 − 9 = 2."],
    "TMP811_2_18": ["Economisești £5 pe săptămână. În câte săptămâni strângi £40?", "Împarte £40 la £5.", ["6", "7", "8", "9"], "£40 ÷ £5 = 8 săptămâni."],
    "TMP811_2_19": ["O imprimantă tipărește 10 pagini pe minut. Cât durează să tipărească 80 de pagini?", "Împarte paginile la paginile pe minut.", ["6 minute", "7 minute", "8 minute", "10 minute"], "80 ÷ 10 = 8 minute."],
    "TMP811_2_20": ["48 de elevi sunt împărțiți în echipe de câte 8. Câte echipe se formează?", "Împarte 48 la 8.", ["4", "5", "6", "7"], "48 ÷ 8 = 6 echipe."],
    "TMP811_3_01": ["Un magazin vinde creioane cu 50p și stilouri cu £1,20. Cumperi 3 creioane și 2 stilouri. Cât plătești?", "Calculează separat fiecare parte, apoi adună.", ["£3.50", "£3.90", "£4.10", "£4.50"], "3 × 50p = £1,50. 2 × £1,20 = £2,40. Total: £1,50 + £2,40 = £3,90."],
    "TMP811_3_02": ["Un păianjen are 8 picioare, un câine 4. Într-o cameră sunt 3 păianjeni și 2 câini. Câte picioare sunt în total?", "Calculează mai întâi picioarele păianjenilor, apoi ale câinilor.", ["28", "30", "32", "36"], "3 × 8 = 24 picioare (păianjeni). 2 × 4 = 8 picioare (câini). 24 + 8 = 32."],
    "TMP811_3_03": ["Ceasul arată 15:45. Ce oră va fi peste 2 ore și 30 de minute?", "Adună mai întâi orele, apoi minutele.", ["17:15", "17:45", "18:15", "18:45"], "15:45 + 2 h = 17:45. 17:45 + 30 min = 18:15."],
    "TMP811_3_04": ["Ai 3 monede: 50p, 20p și 10p. Câte sume diferite poți forma folosind una sau mai multe monede?", "Listează toate combinațiile: câte una, câte două, toate trei.", ["5", "6", "7", "8"], "Singure: 50, 20, 10. Perechi: 70, 60, 30. Toate trei: 80. În total 7 sume."],
    "TMP811_3_05": ["O rețetă cere 250 g de făină pentru 4 persoane. Câtă făină trebuie pentru 12 persoane?", "12 este de 3 ori mai mult decât 4.", ["500 g", "625 g", "750 g", "1000 g"], "12 ÷ 4 = 3 ori mai mult. 250 × 3 = 750 g."],
    "TMP811_3_06": ["Un tren pleacă la 9:15 și ajunge la 11:45. Cât durează călătoria?", "Numără orele și minutele.", ["2 ore", "2 ore și 15 minute", "2 ore și 30 minute", "3 ore"], "De la 9:15 la 11:15 = 2 ore. De la 11:15 la 11:45 = 30 minute. Total: 2 ore și 30 minute."],
    "TMP811_3_07": ["Cumperi produse care costă £2,50, £3,75, £1,25 și £4,50. Cât rest primești din £20?", "Adună toate prețurile, apoi scade din £20.", ["£6.00", "£7.00", "£8.00", "£9.00"], "£2,50 + £3,75 + £1,25 + £4,50 = £12,00. Rest: £20 − £12 = £8,00."],
    "TMP811_3_08": ["Într-o cameră sunt scaune (câte 4 picioare) și taburete (câte 3). Sunt 5 scaune și câteva taburete. În total sunt 29 de picioare. Câte taburete sunt?", "Calculează mai întâi picioarele scaunelor, apoi află taburetele.", ["2", "3", "4", "5"], "5 scaune × 4 = 20 picioare. 29 − 20 = 9 picioare rămase. 9 ÷ 3 = 3 taburete."],
    "TMP811_3_09": ["Durează 5 minute să tai un buștean în 2 bucăți. Cât durează să-l tai în 4 bucăți?", "Pentru 4 bucăți ai nevoie de 3 tăieturi, nu 4.", ["10 minute", "15 minute", "20 minute", "25 minute"], "4 bucăți = 3 tăieturi. 3 × 5 = 15 minute."],
    "TMP811_3_10": ["Un autobuz transportă 45 de pasageri. Pentru o excursie școlară sunt necesare 3 autobuze. Care e numărul maxim de elevi care pot merge?", "Înmulțește locurile pe autobuz cu numărul de autobuze.", ["90", "120", "135", "150"], "3 × 45 = 135 elevi cel mult."],
    "TMP811_3_11": ["Începi cu £100. Cheltuiești un sfert, apoi o treime din ce îți rămâne. Cât îți rămâne?", "Un sfert din 100 = 25. Apoi o treime din 75.", ["£40", "£45", "£50", "£55"], "Sfert din £100 = £25 cheltuiți, rămân £75. O treime din £75 = £25 cheltuiți. £75 − £25 = £50."],
    "TMP811_3_12": ["O ședință începe la 14:50 și durează 1 oră și 25 minute. La ce oră se termină?", "Adună 1 oră, apoi 25 minute.", ["15:55", "16:05", "16:15", "16:25"], "14:50 + 1 h = 15:50. 15:50 + 25 min = 16:15."],
    "TMP811_3_13": ["Într-o clasă sunt de două ori mai multe fete decât băieți. Sunt 12 băieți. Câți copii sunt în total?", "Fete = 2 × băieți.", ["24", "30", "36", "48"], "Fete = 2 × 12 = 24. Total = 12 + 24 = 36 copii."],
    "TMP811_3_14": ["Vrei să împrejmuiești o grădină pătrată cu latura de 8 m. Gardul costă £5 pe metru. Care e costul total?", "Află mai întâi perimetrul, apoi înmulțește cu prețul pe metru.", ["£120", "£140", "£160", "£200"], "Perimetru = 4 × 8 = 32 m. Cost = 32 × £5 = £160."],
    "TMP811_3_15": ["Un film începe la 19:40 și durează 1 oră și 50 minute. La ce oră se termină?", "Adună 1 oră (obții 20:40), apoi 50 minute.", ["21:10", "21:20", "21:30", "21:40"], "19:40 + 1 h = 20:40. 20:40 + 50 min = 21:30."],
    "TMP811_3_16": ["Într-o curte sunt vaci și găini. Numeri 8 capete și 26 de picioare. Câte vaci sunt?", "Vaca are 4 picioare, găina 2. Poți verifica prin încercări.", ["3", "4", "5", "6"], "8 capete. Dacă toate ar fi găini: 8 × 2 = 16 picioare. În plus: 26 − 16 = 10. Fiecare vacă adaugă 2 picioare în plus: 10 ÷ 2 = 5 vaci."],
    "TMP811_3_17": ["Folosind monede de 5p, 10p și 20p, în câte moduri diferite poți face exact 25p?", "Listează toate combinațiile care însumează 25p.", ["2", "3", "4", "5"], "Patru moduri: (1) 20+5, (2) 10+10+5, (3) 10+5+5+5, (4) 5+5+5+5+5."],
    "TMP811_3_18": ["O pistă de alergare are 400 m. Un sportiv aleargă 3 tururi. Câți kilometri parcurge?", "1 km = 1000 m.", ["0,8 km", "1,0 km", "1,2 km", "1,5 km"], "3 × 400 = 1200 m = 1,2 km."],
    "TMP811_3_19": ["O cutie conține 24 bomboane. Ai nevoie pentru 100 de persoane (câte una fiecăruia). Câte cutii trebuie să cumperi?", "4 cutii = 96 (nu ajung). Încearcă 5 cutii.", ["4", "5", "6", "10"], "4 cutii = 96 (nu ajung). 5 cutii = 120 (ajunge). Trebuie să cumperi 5."],
    "TMP811_3_20": ["Două numere au suma 50. Unul este cu 14 mai mare decât celălalt. Care este numărul mai mare?", "Notează numărul mai mic cu x. Atunci x + (x + 14) = 50.", ["28", "30", "32", "36"], "x + (x + 14) = 50. 2x = 36. x = 18. Mai mare = 18 + 14 = 32."],
  }
});
